/// <summary>
/// Handles events related with classes used by accusation.
/// </summary>
class FWFAccusClassEventHandler
{
}

Method.Source:
/// <summary>
/// Do some additinal initialization to <c>InventUpd_Physical</c>.
/// </summary>
/// <param name="_args">The event arguments.</param>
[PostHandlerFor(classStr(InventUpd_Physical), staticMethodStr(InventUpd_Physical, newInventUpdFinancial))]
public static void InventUpd_Physical_Post_newInventUpdFinancial(XppPrePostArgs _args)
{
    InventUpd_Financial inventUpdFinancial = _args.getArg(identifierstr(_financial)) as InventUpd_Financial;
    InventUpd_Physical  inventUpdPhysical  = _args.getReturnValue() as InventUpd_Physical;

    inventUpdPhysical.parmFWFCreditNoteAccusMode(inventUpdFinancial.parmFWFCreditNoteAccusMode());
}

/// <summary>
///
/// </summary>
/// <param name="_args">The event arguments.</param>
[PostHandlerFor(classStr(PurchQuantity), methodStr(PurchQuantity, qtyInvent))]
public static void PurchQuantity_Post_qtyInvent(XppPrePostArgs _args)
{
    if (_args.getThis() is PurchQuantity_Invoice)
    {
        PurchUpdate purchUpdate = _args.getArg(identifierStr(specQty));

        if (purchUpdate == PurchUpdate::FWFAccusInvoicePriceCorrection)
        {
            _args.setReturnValue([0, 0, 0]);
        }
    }
}

/// <summary>
///
/// </summary>
/// <param name="_args">The event arguments.</param>
[PostHandlerFor(classStr(PurchQuantity), methodStr(PurchQuantity, calcInventQty))]
public static void PurchQuantity_Post_calcInventQty(XppPrePostArgs _args)
{
    if (_args.getThis() is PurchQuantity_Invoice)
    {
        PurchUpdate purchUpdate = _args.getArg(identifierStr(specQty));

        if (purchUpdate == PurchUpdate::FWFAccusInvoicePriceCorrection)
        {
            _args.setReturnValue(0);
        }
    }
}

/// <summary>
///
/// </summary>
/// <param name="_args"></param>
[PostHandlerFor(classStr(PurchQuantity), methodStr(PurchQuantity, qtyPurch))]
public static void PurchQuantity_Post_qtyPurch(XppPrePostArgs _args)
{
    if (_args.getThis() is PurchQuantity_Invoice)
    {
        PurchUpdate purchUpdate = _args.getArg(identifierStr(specQty));
        PurchLine   purchLine   = _args.getArg(identifierStr(purchLine)) as PurchLine;

        if (purchUpdate == PurchUpdate::FWFAccusInvoicePriceCorrection)
        {
            _args.setReturnValue([-purchLine.invoicedInTotal(), 0, 0]);
        }
    }
}

/// <summary>
///
/// </summary>
/// <param name="_args"></param>
[PostHandlerFor(classStr(PurchQuantity), methodStr(PurchQuantity, calcPurchQty))]
public static void PurchQuantity_Post_calcPurchQty(XppPrePostArgs _args)
{
    if (_args.getThis() is PurchQuantity_Invoice)
    {
        PurchUpdate purchUpdate = _args.getArg(identifierStr(specQty));
        PurchLine   purchLine   = _args.getArg(identifierStr(purchLine)) as PurchLine;

        if (purchUpdate == PurchUpdate::FWFAccusInvoicePriceCorrection)
        {
            _args.setReturnValue(-purchLine.invoicedInTotal());
        }
    }
}

/// <summary>
///
/// </summary>
/// <param name="_args">The event arguments.</param>
[PreHandlerFor(classStr(PurchFormletterProvider), methodStr(PurchFormletterProvider, checkJournal))]
public static void PurchFormletterProvider_Pre_checkJournal(XppPrePostArgs _args)
{
    PurchFormletterProvider purchFrmLetterProvider = _args.getThis() as PurchFormletterProvider;
    PurchParmUpdate purchParmUpdate = purchFrmLetterProvider.parmParmUpdate() as PurchParmUpdate;

    if (purchParmUpdate.SpecQty == PurchUpdate::FWFAccusInvoicePriceCorrection)
    {
        PurchTotals purchTotals = purchFrmLetterProvider.parmTotals() as PurchTotals;
        RecordSortedList recordListPurchLine;
        PurchLine purchLine;            

        recordListPurchLine = purchTotals.recordListPurchLine();
        recordListPurchLine.first(purchLine);
        while (purchLine)
        {
            purchLine.PurchQty = -purchLine.PurchQty;
            recordListPurchLine.ins(purchLine, true);

            if (!recordListPurchLine.next(purchLine))
            {
                break;
            }
        }

        purchTotals.recordListPurchLine(recordListPurchLine);
    }
}

/// <summary>
///
/// </summary>
/// <param name="_args"></param>
[PostHandlerFor(classStr(formletterParmData), methodStr(formletterParmData, createData))]
public static void formletterParmData_Post_createData(XppPrePostArgs _args)
{
    formletterParmData frmLetterParmData = _args.getThis() as formletterParmData;
    PurchParmUpdate purchParmUpdate = frmLetterParmData.parmParmUpdate() as PurchParmUpdate;

    if (purchParmUpdate.SpecQty == PurchUpdate::FWFAccusInvoicePriceCorrection)
    {
        frmLetterParmData.reSelect();
    }
}
